section.sourcecode:
sealed-object = { 1 => bstr .size 16, ; id: 128-bit random 2 => bstr .size 16, ; scope_id: opaque random identifier 3 => uint, ; format_version (this document: 1) 4 => bstr, ; COSE_Encrypt0 whose plaintext is a ; COSE_Sign1 over memory-payload ? 5 => bstr .size 16, ; dek_wrap_ref (optional) }
memory-payload = { 1 => mem-type, 2 => tstr, ; content (UTF-8 text) 3 => confidence, ; 0.0 .. 1.0 4 => provenance, 5 => trust-level, ? 6 => [* tstr], ; tags 7 => timestamps, ; semantic times: MUST NOT appear ; outside the envelope ? 8 => embedding, ; MUST NOT appear outside the envelope ? 9 => time, ; expires_at ? 10 => {* tstr => any}, ; extensions }
mem-type = &( episodic: 1, semantic: 2, procedural: 3 ) confidence = float .ge 0.0 .le 1.0 provenance = { 1 => tstr, ; producing tool identifier 2 => bstr .size 8, ; author_key_id: first 8 bytes of ; SHA-256 of author's Ed25519 key ? 3 => tstr, ; session identifier } trust-level = &( self: 1, trusted: 2, third-party: 3, unverified: 4 ) timestamps = { 1 => time, ? 2 => time } ; created, updated embedding = { 1 => tstr, 2 => [* float] } ; model, vector

amem-export = {
  1 => uint,              ; export_version (this document: 1)
  2 => vault-public,      ; salt, public keys, wrapped scope KEKs
  3 => [* bstr],          ; sealed-objects (encoded)
  4 => {* bstr => bstr},  ; object id => wrapped DEK
}
vault-public = {
  "salt" => bstr .size 16,
  "sign_pub" => bstr .size 32,
  "ka_pub" => bstr .size 32,
  "scopes" => {* tstr => scope-entry },
}
scope-entry = {
  "scope_id" => bstr .size 16,
  "kek_wrapped" => bstr,
  "eph_pub" => bstr .size 32,
}
